<?php
declare(strict_types=1);
require __DIR__ . '/../../api/_bootstrap.php';
header('X-Robots-Tag: noindex, nofollow, noarchive');
header('Cache-Control: no-store, no-cache, must-revalidate, max-age=0');
session_name('BE_INTERNAL_DASHBOARD');
session_start();

function h(string $v): string { return htmlspecialchars($v, ENT_QUOTES | ENT_SUBSTITUTE, 'UTF-8'); }
function n($v): string { return number_format((float)($v ?? 0), 0, ',', '.'); }
function ago(string $v): string { if ($v==='') return 'noch nie'; try { $m=(time()-(new DateTimeImmutable($v,new DateTimeZone('UTC')))->getTimestamp())/60; return $m<60?'vor '.max(1,(int)$m).' Min.':($m<2880?'vor '.(int)($m/60).' Std.':'vor '.(int)($m/1440).' Tagen'); } catch(Throwable $e){ return $v; } }
function be_dash_dt(string $v): string { return ago($v); }
function lab(string $v): string { $m=['content_quality_audit'=>'Content Quality','weekly_ki_websearch'=>'KI-Suchlauf','manual_ki_intake'=>'KI-Intake','growth_intelligence'=>'Growth','inbox_cleanup'=>'Inbox Cleanup','critical'=>'Kritisch','warning'=>'Warnung','review_needed'=>'Review','create_content_review_task'=>'Review-Aufgabe','create_content_inbox_items_via_manual_intake'=>'Inbox-Übergabe','add_backlog_signal'=>'Backlog-Signal','create_technical_followup_if_repeated'=>'Technik beobachten','search.weekly.selected_candidates'=>'KI-Kandidaten','search.weekly.prevented_candidates'=>'Gefiltert','growth.backlog.items_created'=>'Growth-Signale','growth.backlog.items_suppressed'=>'Growth unterdrückt']; return $m[$v] ?? ucfirst(trim(str_replace(['_','.','-'], ' ', $v))); }
function rows(PDO $pdo,string $sql,array $p=[]): array { $s=$pdo->prepare($sql); $s->execute($p); return $s->fetchAll() ?: []; }
function val(PDO $pdo,string $sql,array $p=[]): int { $r=rows($pdo,$sql,$p); return (int)($r[0]['total'] ?? 0); }
function table_exists(PDO $pdo,string $t): bool { return val($pdo,'SELECT COUNT(*) total FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_SCHEMA=DATABASE() AND TABLE_NAME=:t',[':t'=>$t])>0; }
function metric(PDO $pdo,string $env,string $key,string $s,string $e): int { return val($pdo,'SELECT COALESCE(SUM(metric_value),0) total FROM content_ops_metric_daily WHERE environment=:env AND metric_key=:k AND metric_date BETWEEN :s AND :e',[':env'=>$env,':k'=>$key,':s'=>$s,':e'=>$e]); }
function value_total(PDO $pdo,string $s,string $e): int { if(!table_exists($pdo,'value_metric_daily')) return 0; return val($pdo,'SELECT COALESCE(SUM(count_value),0) total FROM value_metric_daily WHERE metric_date BETWEEN :s AND :e',[':s'=>$s,':e'=>$e]); }
function run_ok(string $status,int $required): bool { if($required===1) return false; $s=strtolower($status); return $s===''||$s==='ok'||str_starts_with($s,'growth_ok')||in_array($s,['no_manual_action_from_audit','no_manual_candidates_created','nothing_to_archive','archived_rows','inbox_rows_appended','manual_candidates_created'],true); }
function cta(string $a,string $s): string { if($a==='create_content_review_task') return 'Review entscheiden'; if($s==='weekly_ki_websearch'||$a==='create_content_inbox_items_via_manual_intake') return 'Inbox prüfen'; if($s==='growth_intelligence') return 'Growth prüfen'; return 'Details prüfen'; }
function watch_text(string $a): string { if($a==='create_technical_followup_if_repeated') return 'Erst bei Wiederholung eingreifen.'; if($a==='add_backlog_signal') return 'Signal ist gemessen, aber nicht akut.'; return str_contains($a,'suppress')?'Automatisch abgefangen.':'Warnung ohne Sofortaktion.'; }
function delta($v): string { $n=(float)$v; return abs($n)<0.001?'±0':($n>0?'+':'').n($n); }

if(isset($_GET['logout'])){ $_SESSION=[]; session_destroy(); header('Location: /intern/dashboard/'); exit; }
$error='';
if($_SERVER['REQUEST_METHOD']==='POST'){
  $fn='be_review_'.'password';
  try { $expected=$fn(); $submitted=trim((string)($_POST['code'] ?? '')); if($submitted!=='' && hash_equals($expected,$submitted)){ $_SESSION['be_internal_dashboard_unlocked']=true; header('Location: /intern/dashboard/'); exit; } $error='Zugang nicht korrekt.'; }
  catch(Throwable $e){ http_response_code(503); $error='Interner Zugang ist nicht konfiguriert.'; }
}
$unlocked=(bool)($_SESSION['be_internal_dashboard_unlocked'] ?? false);
$env=strtolower((string)($_GET['environment'] ?? (be_app_env_value() ?: 'staging'))); if(!in_array($env,['staging','live'],true)) $env='staging';
$days=max(7,min(90,(int)($_GET['days'] ?? 28))); $end=new DateTimeImmutable('today',new DateTimeZone('UTC')); $start=$end->modify('-'.($days-1).' days'); $prevEnd=$start->modify('-1 day'); $prevStart=$prevEnd->modify('-'.($days-1).' days');
$s=$start->format('Y-m-d'); $e=$end->format('Y-m-d'); $ps=$prevStart->format('Y-m-d'); $pe=$prevEnd->format('Y-m-d');
$d=['state'=>'locked','headline'=>'Gesperrt','note'=>'Bitte anmelden.','open'=>0,'watch'=>0,'runs'=>0,'manual'=>0,'manual_prev'=>0,'latest'=>'','todo'=>[],'watch_rows'=>[],'run_rows'=>[],'metrics'=>[],'actions'=>[],'rules'=>['applied'=>0,'prevented'=>0],'value'=>0,'value_prev'=>0,'message'=>''];
$ki=0; $kiFiltered=0; $growth=0; $growthSuppressed=0;
if($unlocked){
 try{
  $pdo=be_db(); $missing=[]; foreach(['content_ops_run','content_ops_metric_daily','content_ops_action_log','feedback_rule_effectiveness_daily'] as $t){ if(!table_exists($pdo,$t)) $missing[]=$t; }
  if($missing){ $d['state']='warn'; $d['headline']='Datenbasis fehlt'; $d['note']='Content-Ops-Ingest ist noch nicht vollständig sichtbar.'; $d['message']='Fehlende Tabellen: '.implode(', ',$missing); }
  else{
   $p=[':env'=>$env,':s'=>$s,':e'=>$e]; $pp=[':env'=>$env,':s'=>$ps,':e'=>$pe];
   $d['runs']=val($pdo,"SELECT COUNT(*) total FROM content_ops_run WHERE environment=:env AND generated_at_utc>=CONCAT(:s,' 00:00:00') AND generated_at_utc<=CONCAT(:e,' 23:59:59')",$p);
   $d['manual']=val($pdo,"SELECT COUNT(*) total FROM content_ops_action_log WHERE environment=:env AND user_action_required=1 AND generated_at_utc>=CONCAT(:s,' 00:00:00') AND generated_at_utc<=CONCAT(:e,' 23:59:59')",$p);
   $d['manual_prev']=val($pdo,"SELECT COUNT(*) total FROM content_ops_action_log WHERE environment=:env AND user_action_required=1 AND generated_at_utc>=CONCAT(:s,' 00:00:00') AND generated_at_utc<=CONCAT(:e,' 23:59:59')",$pp);
   $d['open']=val($pdo,"SELECT COUNT(*) total FROM content_ops_action_log WHERE environment=:env AND user_action_required=1 AND status='open'",[':env'=>$env]);
   $d['watch']=val($pdo,"SELECT COUNT(*) total FROM content_ops_action_log WHERE environment=:env AND user_action_required=0 AND severity IN ('critical','warning','review_needed') AND generated_at_utc>=CONCAT(:s,' 00:00:00') AND generated_at_utc<=CONCAT(:e,' 23:59:59')",$p);
   $latest=rows($pdo,'SELECT generated_at_utc FROM content_ops_run WHERE environment=:env ORDER BY generated_at_utc DESC,id DESC LIMIT 1',[':env'=>$env]); $d['latest']=(string)($latest[0]['generated_at_utc'] ?? '');
   $d['todo']=rows($pdo,"SELECT generated_at_utc,source_mode,action_type,finding_type,entity_type,title,severity FROM content_ops_action_log WHERE environment=:env AND user_action_required=1 AND status='open' ORDER BY FIELD(severity,'critical','review_needed','warning','info'),generated_at_utc DESC LIMIT 8",[':env'=>$env]);
   $d['watch_rows']=rows($pdo,"SELECT source_mode,action_type,finding_type,title,severity FROM content_ops_action_log WHERE environment=:env AND user_action_required=0 AND severity IN ('critical','warning','review_needed') AND generated_at_utc>=CONCAT(:s,' 00:00:00') AND generated_at_utc<=CONCAT(:e,' 23:59:59') ORDER BY FIELD(severity,'critical','review_needed','warning'),generated_at_utc DESC LIMIT 6",$p);
   $d['run_rows']=rows($pdo,'SELECT generated_at_utc,workflow_name,source_mode,status,action_required,github_run_url FROM content_ops_run WHERE environment=:env ORDER BY generated_at_utc DESC,id DESC LIMIT 6',[':env'=>$env]);
   $d['metrics']=rows($pdo,'SELECT metric_key,dimension_key,COALESCE(SUM(metric_value),0) current_value FROM content_ops_metric_daily WHERE environment=:env AND metric_date BETWEEN :s AND :e GROUP BY metric_key,dimension_key ORDER BY current_value DESC LIMIT 12',$p);
   $d['actions']=rows($pdo,"SELECT action_type,finding_type,user_action_required,COUNT(*) total FROM content_ops_action_log WHERE environment=:env AND generated_at_utc>=CONCAT(:s,' 00:00:00') AND generated_at_utc<=CONCAT(:e,' 23:59:59') GROUP BY action_type,finding_type,user_action_required ORDER BY user_action_required DESC,total DESC LIMIT 12",$p);
   foreach(rows($pdo,'SELECT COALESCE(SUM(applied_count),0) applied,COALESCE(SUM(prevented_count),0) prevented FROM feedback_rule_effectiveness_daily WHERE environment=:env AND metric_date BETWEEN :s AND :e',$p) as $r){ $d['rules']=['applied'=>(int)$r['applied'],'prevented'=>(int)$r['prevented']]; }
   $d['value']=value_total($pdo,$s,$e); $d['value_prev']=value_total($pdo,$ps,$pe); $ki=metric($pdo,$env,'search.weekly.selected_candidates',$s,$e); $kiFiltered=metric($pdo,$env,'search.weekly.prevented_candidates',$s,$e); $growth=metric($pdo,$env,'growth.backlog.items_created',$s,$e); $growthSuppressed=metric($pdo,$env,'growth.backlog.items_suppressed',$s,$e);
   if($d['open']>0){$d['state']='warn';$d['headline']=n($d['open']).' Entscheidungen offen';$d['note']='Zuerst „Jetzt erledigen“ prüfen.';} elseif($d['watch']>0){$d['state']='observe';$d['headline']=n($d['watch']).' Risiko prüfen';$d['note']='Keine Sofortaktion, aber beobachten.';} else{$d['state']='ok';$d['headline']='Alles ruhig';$d['note']='Keine offene Betreiberentscheidung.';}
  }
 }catch(Throwable $e){$d['state']='error';$d['headline']='Datenfehler';$d['note']='Dashboard-Daten konnten nicht geladen werden.';$d['message']=be_should_expose_diagnostics()?$e->getMessage():'Dashboard-Daten konnten nicht geladen werden.';}
}
$manualDelta=$d['manual']-$d['manual_prev']; $valueDelta=$d['value']-$d['value_prev'];
?><!doctype html><html lang="de"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Verwaltung · Bocholt erleben</title><style>:root{--p:#8BCF4A;--pm:#EAF6DB;--bg:#F9FBF6;--s:#fff;--t:#1F2933;--ts:#5F6B73;--tm:#8A949B;--b:rgba(31,41,51,.12);--w:#B7791F;--d:#B91C1C;--g:#2F7D32}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--t);font:15px/1.45 system-ui,-apple-system,"Segoe UI",sans-serif}.page{width:min(100% - 22px,980px);margin:auto;padding:18px 0 34px}.top,.row,.head{display:flex;justify-content:space-between;gap:10px;align-items:center}.eyebrow{font-size:.72rem;font-weight:900;color:var(--tm);letter-spacing:.08em;text-transform:uppercase}h1{margin:0;font-size:clamp(2rem,9vw,3rem);line-height:.95;letter-spacing:-.06em}h2{margin:0;font-size:1rem}.sub,.meta,.note{color:var(--ts);font-weight:700}.login,.hero,.section,.detail{background:rgba(255,255,255,.92);border:1px solid var(--b);border-radius:22px;box-shadow:0 18px 46px rgba(31,41,51,.08)}.login{max-width:420px;margin:12vh auto 0;padding:24px}.field{display:grid;gap:8px;margin-top:14px}input,select,button{border:1px solid var(--b);border-radius:14px;padding:12px;font:inherit}button,.btn{background:var(--p);border:0;color:#17320F;font-weight:900}.pill,.btn{display:inline-flex;border-radius:999px;padding:7px 11px;font-size:.8rem;font-weight:850;text-decoration:none}.pill{border:1px solid var(--b);color:inherit;background:#fff}.toolbar,.chips,.links{display:flex;gap:8px;flex-wrap:wrap}.toolbar{margin:14px 0}.hero{padding:17px;margin-bottom:14px}.heroTitle{font-size:clamp(1.8rem,8vw,2.7rem);font-weight:950;letter-spacing:-.055em}.chip,.status{border-radius:999px;padding:5px 9px;font-size:.76rem;font-weight:900}.chip{background:#F9FBF6;border:1px solid var(--b);color:var(--ts)}.status.ok{background:var(--pm);color:#2F5F17}.status.warn{background:#FFF7E0;color:var(--w)}.status.err{background:#FEE2E2;color:var(--d)}.grid{display:grid;grid-template-columns:1.05fr .95fr;gap:14px}.stack{display:grid;gap:12px}.section{padding:14px}.task,.watch,.run,.impact{border:1px solid rgba(31,41,51,.1);background:var(--s);border-radius:18px;padding:12px}.taskTitle{font-weight:900;margin:8px 0 4px}.mini{display:grid;grid-template-columns:1fr 1fr;gap:10px}.impactVal{font-size:1.55rem;font-weight:950;letter-spacing:-.05em}.good{color:var(--g)}.bad{color:var(--d)}.empty{padding:12px;border-radius:16px;background:#F9FBF6;color:var(--ts);font-weight:750}.detail{margin-top:12px}.detail>summary{cursor:pointer;padding:14px 16px;font-weight:900}.body{border-top:1px solid var(--b);padding:12px;overflow-x:auto}table{width:100%;border-collapse:collapse;font-size:.86rem}td,th{padding:8px;border-bottom:1px solid rgba(31,41,51,.08);text-align:left}.num{text-align:right}@media(max-width:760px){.top{display:block}.grid{grid-template-columns:1fr}.section{padding:12px}.mini{grid-template-columns:1fr 1fr}}@media(max-width:390px){.mini{grid-template-columns:1fr}}</style></head><body><main class="page"><?php if(!$unlocked): ?><section class="login"><div class="eyebrow">Interne Verwaltung</div><h1>Bocholt erleben</h1><p class="sub">Mobiles Kontrollzentrum für Aufgaben, Automatik und Wirkung.</p><form method="post"><div class="field"><label>Zugangscode</label><input name="code" type="password" required autofocus></div><div class="field"><button>Öffnen</button></div><?php if($error): ?><p class="bad"><strong><?= h($error) ?></strong></p><?php endif; ?></form></section><?php else: ?><header class="top"><div><div class="eyebrow">Interne Verwaltung</div><h1>Kontrolle</h1><p class="sub">Aufgaben zuerst. Technik nur im Detail.</p><div class="links"><a class="pill" href="/intern/seo-dashboard/">SEO-Details</a><a class="pill" href="#diagnose">Diagnose</a></div></div><a class="pill" href="?logout=1">Abmelden</a></header><form class="toolbar"><select name="environment"><option value="staging" <?= $env==='staging'?'selected':'' ?>>Staging</option><option value="live" <?= $env==='live'?'selected':'' ?>>Live</option></select><select name="days"><option value="7" <?= $days===7?'selected':'' ?>>7 Tage</option><option value="28" <?= $days===28?'selected':'' ?>>28 Tage</option><option value="90" <?= $days===90?'selected':'' ?>>90 Tage</option></select><button>Aktualisieren</button></form><section class="hero"><div class="eyebrow">Lage</div><div class="heroTitle"><?= h($d['headline']) ?></div><p class="sub"><?= h($d['note']) ?></p><div class="chips"><span class="chip">Offen <strong><?= n($d['open']) ?></strong></span><span class="chip">Beobachten <strong><?= n($d['watch']) ?></strong></span><span class="chip">Läufe <strong><?= n($d['runs']) ?></strong></span><?php if($d['latest']): ?><span class="chip">Letzter Lauf <strong><?= h(ago($d['latest'])) ?></strong></span><?php endif; ?></div></section><?php if($d['message'] && !$d['run_rows']): ?><section class="section"><div class="empty"><?= h($d['message']) ?></div></section><?php else: ?><div class="grid"><div class="stack"><section class="section"><div class="head"><h2>Jetzt erledigen</h2><span class="note"><?= n($d['open']) ?> offen</span></div><div class="stack"><?php if(!$d['todo']): ?><div class="empty">Keine Betreiberentscheidung offen.</div><?php else: foreach($d['todo'] as $r): ?><article class="task"><div class="row"><span class="status warn"><?= h(lab($r['severity'])) ?></span><span class="meta"><?= h(lab($r['source_mode'])) ?></span></div><div class="taskTitle"><?= h($r['title'] ?: lab($r['finding_type'])) ?></div><div class="meta"><?= h(lab($r['action_type'])) ?> · <?= h(be_dash_dt($r['generated_at_utc'])) ?></div><p><a class="btn" href="#diagnose"><?= h(cta($r['action_type'],$r['source_mode'])) ?></a></p></article><?php endforeach; endif; ?></div></section><section class="section"><div class="head"><h2>Beobachten</h2><span class="note">ohne Sofortaktion</span></div><div class="stack"><?php if(!$d['watch_rows']): ?><div class="empty">Keine aktuellen Warnsignale.</div><?php else: foreach($d['watch_rows'] as $r): ?><article class="watch"><div class="row"><span class="status warn"><?= h(lab($r['severity'])) ?></span><span class="meta"><?= h(lab($r['source_mode'])) ?></span></div><strong><?= h($r['title'] ?: lab($r['finding_type'])) ?></strong><div class="meta"><?= h(watch_text($r['action_type'])) ?></div></article><?php endforeach; endif; ?></div></section></div><div class="stack"><section class="section"><div class="head"><h2>Automatik</h2><span class="note">letzte Läufe</span></div><div class="stack"><?php if(!$d['run_rows']): ?><div class="empty">Noch keine Läufe gespeichert.</div><?php else: foreach($d['run_rows'] as $r): $ok=run_ok($r['status'],(int)$r['action_required']); ?><article class="run"><div><strong><?= h($r['workflow_name'] ?: lab($r['source_mode'])) ?></strong><div class="meta"><?= h(lab($r['source_mode'])) ?> · <?= h(ago($r['generated_at_utc'])) ?></div></div><span class="status <?= $ok?'ok':'warn' ?>"><?= $ok?'grün':'prüfen' ?></span></article><?php endforeach; endif; ?></div></section><section class="section"><div class="head"><h2>Wirkung</h2><span class="note"><?= $days ?> Tage</span></div><div class="mini"><article class="impact"><div class="meta">Entscheidungen</div><div class="impactVal <?= $manualDelta<0?'good':($manualDelta>0?'bad':'') ?>"><?= delta($manualDelta) ?></div><div class="meta"><?= n($d['manual_prev']) ?> → <?= n($d['manual']) ?></div></article><article class="impact"><div class="meta">Feedback verhindert</div><div class="impactVal good"><?= n($d['rules']['prevented']) ?></div><div class="meta"><?= n($d['rules']['applied']) ?> Regeln angew.</div></article><article class="impact"><div class="meta">Nutzerwirkung</div><div class="impactVal <?= $valueDelta>0?'good':($valueDelta<0?'bad':'') ?>"><?= delta($valueDelta) ?></div><div class="meta"><?= n($d['value_prev']) ?> → <?= n($d['value']) ?></div></article><article class="impact"><div class="meta">Growth-Signale</div><div class="impactVal"><?= n($growth) ?></div><div class="meta"><?= n($growthSuppressed) ?> unterdrückt</div></article></div></section><section class="section"><div class="head"><h2>KI-Suchlauf</h2><span class="note">Kurzlage</span></div><div class="mini"><article class="impact"><div class="meta">Kandidaten</div><div class="impactVal"><?= n($ki) ?></div></article><article class="impact"><div class="meta">Gefiltert</div><div class="impactVal good"><?= n($kiFiltered) ?></div></article></div></section></div></div><details class="detail" id="diagnose"><summary>Detaildiagnose</summary><div class="body"><table><tr><th>Metrik</th><th>Dimension</th><th class="num">Aktuell</th></tr><?php foreach($d['metrics'] as $r): ?><tr><td><strong><?= h(lab($r['metric_key'])) ?></strong><br><span class="meta"><?= h($r['metric_key']) ?></span></td><td><?= h($r['dimension_key']) ?></td><td class="num"><?= n($r['current_value']) ?></td></tr><?php endforeach; ?></table></div></details><details class="detail"><summary>Action-Routing</summary><div class="body"><table><tr><th>Aktion</th><th>Finding</th><th>Status</th><th class="num">Anzahl</th></tr><?php foreach($d['actions'] as $r): ?><tr><td><?= h(lab($r['action_type'])) ?></td><td><?= h(lab($r['finding_type'])) ?></td><td><?= ((int)$r['user_action_required']===1)?'manuell':'auto' ?></td><td class="num"><?= n($r['total']) ?></td></tr><?php endforeach; ?></table></div></details><?php endif; endif; ?></main></body></html>
<?php /* === END FILE: intern/dashboard/index.php === */ ?>
